      frontTire:'ti-specialized-butcher-t9-29-23', rearTire:'ti-specialized-eliminator-29-23-gridtrail-t7',
      shifter:'sft-sram-x0-transmission', derailleur:'dr-sram-x0-transmission', cassette:'ca-sram-xs1295',
      chain:'ch-sram-x0-flattop', crankset:'cr-sram-x0-transmission', bb:'bb-sram-dub-bsa73',
