/** Resolve a possibly-legacy part id to its current catalog id.
 * @param {string|null|undefined} id @returns {string|null|undefined} */
function canonicalId(id){ return (id && Object.prototype.hasOwnProperty.call(ALIASES, id)) ? ALIASES[id] : id; }

/* ---- lookups ------------------------------------------------------------- */
/* id -> part index, memoized like _PARTS_BY_CAT (the catalog is immutable at
   runtime). byId is on every hot path - resolveBuild, buildTotals, partWeight,
   partVerified, the UI render loop - and the old linear scan cost O(PARTS)
   per call, which at 3000+ rows dominated every catalog render. Built on a
   null-prototype object so a crafted id ('__proto__', 'toString') can never
   resolve to an inherited value - same hardening posture as sanitizeShare. */
/** @type {Object.<string, Part>|null} */
var _BY_ID = null;
/** @param {string|null|undefined} id @returns {Part|null} */
function byId(id){
  if(!_BY_ID){
    /** @type {Object.<string, Part>} */ var acc = Object.create(null);
    for (var i=0;i<PARTS.length;i++){ acc[PARTS[i].id] = PARTS[i]; }
    _BY_ID = acc;
  }
  return (id && _BY_ID[id]) || null;
}
/** @param {Part|null|undefined} p @returns {string} */
function nameOf(p){ return p ? (p.brand+' '+p.model) : ''; }

/* ---- rotor-class tolerance (rule 10/10b) --------------------------------
   SRAM and Shimano label the SAME physical rotor mount class differently:
   SRAM 200mm === Shimano 203mm, and SRAM 220mm === Shimano 223mm (identical
   6-bolt/Center-Lock caliper position; the ~1.5-3mm radius difference is
   absorbed by the mount). A strict numeric compare against a frame/fork's
   stated max or min rotor size therefore false-flags a same-class rotor
   labeled by the other brand's convention.
   A 3mm grace band is safe: every within-class pair differs by exactly 3mm
   (200<->203, 220<->223), while the smallest gap between two genuinely
   DIFFERENT classes is 17mm (203->220) - so this tolerance can never mask a
   truly oversized/undersized rotor. Kept strict (>3, not >=3) so a 203 on a
   200 max (200-based diff of exactly 3) reads as same-class and does not warn. */
/** @param {number} size @param {number} max @returns {boolean} */
function rotorOverMax(size, max){ return size - max > 3; }
/** @param {number} size @param {number} min @returns {boolean} */
function rotorUnderMin(size, min){ return min - size > 3; }

/* ---- short spec line for a part ----------------------------------------- */
/** @param {Part} p @returns {string} */
function specSummary(p){
  switch(p.cat){
    case 'frame': return p.wheelConfigs.map(function(w){return L(w);}).join(' / ')
      +(p.suspension==='hardtail'
        ? ' . hardtail . '+L(p.rearAxle)
        : ' . '+p.travel+'mm . '+L(p.rearAxle)+' . shock '+p.shockEye+'x'+p.shockStroke+' '+L(p.shockMount))
      +(p.udh?' . UDH':'');
    case 'fork': return L(p.wheel)+' . '+p.travel+'mm . '+L(p.axle)+' . '+L(p.steerer);
    case 'shock': return p.eye+'x'+p.stroke+' . '+L(p.mount)+' . '+p.spring+(p.oemOnly?' . OEM-only':'');
    case 'frontwheel': return L(p.wheel)+' . '+L(p.hub)+' . '+L(p.rotorMount)+' . '+p.intWidth+'mm';
    case 'rearwheel': return L(p.wheel)+' . '+L(p.hub)+' . '+L(p.freehub)+' . '+L(p.rotorMount);
    case 'fronthub': return L(p.hub)+' . '+L(p.rotorMount);
    case 'rearhub': return L(p.hub)+' . '+L(p.freehub)+' . '+L(p.rotorMount);
    case 'rim': return L(p.wheel)+' . '+p.intWidth+'mm . max '+p.maxTire+'in';
    case 'tire': return L(p.wheel)+' . '+p.width+'in'+(p.casing?' . '+L(p.casing):'')+(p.compound?' . '+L(p.compound):'');
    case 'shifter': return L(p.system)+' . '+p.speeds+'s . '+L(p.actuation)+(p.clampType?' . '+L(p.clampType):'');
    case 'derailleur': return L(p.system)+' . '+p.speeds+'s . '+L(p.actuation)+' . '+p.maxCog+'T max . '+L(p.mount);
    case 'cassette': return L(p.freehub)+' . '+p.minCog+'-'+p.maxCog+'T . '+p.speeds+'s';   // range string derived, never stored
    /* chain/crankset: geared rows render exactly as before; the single-speed
       shape (chainWidth, no system/speeds - 2026-07-13 DJ pass) gets its own
       line instead of printing "undefined". */
    case 'chain': return (p.system && typeof p.speeds==='number')
      ? L(p.system)+' . '+p.speeds+'s'
      : (p.chainWidth ? p.chainWidth+'in single-speed'+(p.halfLink?' . half-link':'') : 'chain');
    case 'bb': return L(p.shell)+' shell . '+L(p.spindle)+' spindle';
    case 'headset': return p.upper+' / '+p.lower+' . '+L(p.steerer);   // S.H.I.S. codes self-label
    case 'crankset': return L(p.bb)+(typeof p.ring==='number'?' . '+p.ring+'T':'')
      +(typeof p.speeds==='number'?' . '+p.speeds+'s':'')
      +(p.chainWidth?' . '+p.chainWidth+'in single-speed':'')
      +(p.ringStd ? ' . '+L(p.ringStd)+' ring' : (p.chainWidth ? '' : ' . ring sold separately'));
    case 'cog': return p.teeth+'T . '+p.chainWidth+'in';
    case 'seatpost': return p.diameter+'mm . rigid post';
    case 'brake': return L(p.mount)+' . '+p.pistons+'-piston'
      +(p.leverAccepts && p.leverAccepts.length ? ' . '+p.leverAccepts.map(function(c){return L(c);}).join('/') : '');
    case 'rotor': return p.size+'mm . '+L(p.mount);
    case 'handlebar': return p.clamp+'mm clamp . '+p.width+'mm . '+p.material;
    case 'stem': return p.clamp+'mm clamp . '+p.length+'mm';
    case 'grips': return 'grips';   // honest: an attach field (lock-on/slide-on) is on the capture list; 'lock-on' was false for slide-on silicone grips
    case 'dropper': return p.diameter+'mm . '+p.drop+'mm drop';
    case 'saddle': return 'saddle';
    case 'pedal': return L(p.style)+' . pair';
    case 'groupset': case 'wheelset': case 'brakeset': case 'cockpitset': return p.desc || 'preset';
    case 'completebike': return Object.keys(p.fills).length+' parts . $'+p.price.toLocaleString()+(p.streetPrice?' ($'+p.streetPrice.toLocaleString()+' street)':'');
    default: return '';
  }
}

/* =============================================================================
   COMPATIBILITY ENGINE -> { errors, warnings, infos }
   build keyed by SLOT (frame, fork, shock, frontWheel, rearWheel, frontTire,
   rearTire, ...) -> part object.
   ========================================================================== */
/* Structured verdicts (DATA-MODEL-REVIEW 5.1-18): every finding carries a
   stable ruleId + the slot keys involved, replacing string identity. The
   REVIEW.md #4/#13 maskings were BYTE-IDENTICAL STRINGS raised by different
   conflicts; the dots now diff on verdictKey (ruleId+slots+msg), which cannot
   collide across different slot sets. msg stays the display string (and
   toString), so the UI/report code keeps interpolating verdicts unchanged.
   `fix` is reserved for the "fits with adapter X" tier - adapter facts are
   properties of standards PAIRS and belong in a future engine-side table,
   never on parts. */
/** @typedef {import('./types.js').Verdict} VerdictShape */
/** @constructor @param {string} ruleId @param {string[]} slots @param {string} msg @param {{kind: string, name: string}} [fix] */
function Verdict(ruleId, slots, msg, fix){ this.ruleId=ruleId; this.slots=slots; this.msg=msg; this.fix=fix; }
Verdict.prototype.toString = function(){ return this.msg; };
/** Identity for conflict diffing. @param {VerdictShape} v @returns {string} */
function verdictKey(v){ return v.ruleId+'|'+v.slots.join('+')+'|'+v.msg; }

/* Input guard (pass-4 regression, 2026-07-08): checkBuild/buildTotals take a
   map of slotKey -> resolved Part OBJECT. A caller passing id STRINGS used to
   trip no rule at all - every field read on a string is undefined - so a
   rotor-mismatch build came back 0 errors / 0 warnings: a silent false
   all-clear, the one verdict this product must never give. String values now
   resolve through canonicalId()+byId() (the same forgiving-input path as
   ALIASES and share links); a string that matches no catalog part THROWS,
   because dropping it would just re-create the silent green. */
/** @param {Build|Object.<string, Part|string|null|undefined>|null|undefined} build @returns {Build} */
function resolveBuild(build){
  var src = build || {};
  /** @type {Build} */ var out = {};
  Object.keys(src).forEach(function(k){
    var v = src[k];
    if(typeof v === 'string'){
      var p = byId(canonicalId(v));
      if(!p) throw new TypeError('build.'+k+' is the string "'+v+'", which matches no catalog part id - pass part objects (byId(id)), not ids.');
      out[k] = p;
    } else if(v){
      out[k] = v;
    }
  });
  return out;
}

/* Build-your-own-wheel support (fronthub/rearhub/rim, additive alongside the
   complete frontwheel/rearwheel parts - see GROUPS' `altOf` tag). Every rule
   below reads the front/rear wheel's fields off ONE local (fW/rW); this
   resolver is the single pivot point that lets those rules stay unchanged
   whether the user picked a complete wheel or a hub+rim pair. Returns null if
   neither path is fully filled - callers already treat a missing wheel as
   "nothing to check yet". */
/** @param {Build} b @param {'front'|'rear'} side @returns {EffectiveWheel|null} */
function effectiveWheel(b, side){
  if(side==='front'){
    if(b.frontWheel) return b.frontWheel;
    var fh=b.frontHub, fr=b.frontRim;
    if(!fh || !fr) return null;
    return { wheel:fr.wheel, hub:fh.hub, rotorMount:fh.rotorMount, intWidth:fr.intWidth, maxTire:fr.maxTire, minTire:fr.minTire };
  }
  if(b.rearWheel) return b.rearWheel;
  var rh=b.rearHub, rr=b.rearRim;
  if(!rh || !rr) return null;
  return { wheel:rr.wheel, hub:rh.hub, freehub:rh.freehub, rotorMount:rh.rotorMount, intWidth:rr.intWidth, maxTire:rr.maxTire, minTire:rr.minTire };
}

/** The head-tube-side token of an S.H.I.S. code ('ZS56/28.6' -> 'ZS56'): cup
 * family + bore, the part of the code that is a FRAME fact. Rule 20b compares
 * only this token - the number after the slash is the steerer interface at
 * that assembly, which is the headset row's own consistency (validator
 * cross-rule) + rule 20a's business. The frame backfill's suffixes assume the
 * common tapered assembly (a straight-dc frame like the Supreme DH records
 * ZS56/40), so a full-code match would false-red a real DH headset whose
 * bores fit. @param {string} code @returns {string} */
function shisBore(code){ return String(code).split('/')[0]; }

/** @param {Build} build @returns {CompatResult} */
function checkBuild(build){
  /** @type {VerdictShape[]} */ var errors=[];
  /** @type {VerdictShape[]} */ var warnings=[];
  /** @type {VerdictShape[]} */ var infos=[];
  /** @param {string} ruleId @param {string[]} slots @param {string} msg */
  function err(ruleId, slots, msg){ errors.push(new Verdict(ruleId, slots, msg)); }
  /** @param {string} ruleId @param {string[]} slots @param {string} msg @param {{kind: string, name: string}} [fix] */
  function warn(ruleId, slots, msg, fix){ warnings.push(new Verdict(ruleId, slots, msg, fix)); }
  /** @param {string} ruleId @param {string[]} slots @param {string} msg */
  function info(ruleId, slots, msg){ infos.push(new Verdict(ruleId, slots, msg)); }
  /** @type {Build} */ var b = resolveBuild(build);
  var frame=b.frame, fork=b.fork, shock=b.shock, fW=effectiveWheel(b,'front'), rW=effectiveWheel(b,'rear'), fTire=b.frontTire, rTire=b.rearTire,
      shifter=b.shifter, derailleur=b.derailleur, cassette=b.cassette, chain=b.chain, crankset=b.crankset, cog=b.cog,
      fBrake=b.frontBrake, rBrake=b.rearBrake, fRotor=b.frontRotor, rRotor=b.rearRotor,
      bar=b.handlebar, stem=b.stem, dropper=b.dropper, seatpost=b.seatpost, bb=b.bb, hset=b.headset;   // hset: 'headset' would shadow nothing, but frame.headset (steerer-fit) reads too alike

  /* 1. Wheel sizing: front group + rear group must each be consistent, and the
        front/rear combo must match a config the frame supports (incl. mullet). */
  /** list entries: [display label, wheel size, slot key]
   * @param {string[][]} list @param {string} label @param {string} ruleId @returns {string|null} */
  function sizeOf(list, label, ruleId){
    if(!list.length) return null;
    var ref=list[0][1];
    if(list.some(function(s){ return s[1]!==ref; })){ err(ruleId, list.map(function(s){ return s[2]; }), label+' wheel size mismatch: '+list.map(function(s){ return s[0]+' '+L(s[1]); }).join(', ')+'.'); return null; }
    return ref;
  }
  var frontList=/** @type {string[][]} */([]); if(fork) frontList.push(['Fork',fork.wheel,'fork']); if(fW) frontList.push(['Front wheel',fW.wheel,'frontWheel']); if(fTire) frontList.push(['Front tire',fTire.wheel,'frontTire']);
  var rearList=/** @type {string[][]} */([]);  if(rW) rearList.push(['Rear wheel',rW.wheel,'rearWheel']); if(rTire) rearList.push(['Rear tire',rTire.wheel,'rearTire']);
  var frontSize=sizeOf(frontList,'Front','front-wheel-size'), rearSize=sizeOf(rearList,'Rear','rear-wheel-size');
  if(frame && (frontSize || rearSize)){
    var configs = frame.wheelConfigs || [];
    var okCfg = configs.some(function(cfg){ var c=WHEEL_CONFIG[cfg]; return c && (!frontSize||frontSize===c.front) && (!rearSize||rearSize===c.rear); });
    if(!okCfg) err('wheel-config', ['frame'].concat(frontList.concat(rearList).map(function(s){ return s[2]; })), 'Unsupported wheel setup: '+nameOf(frame)+' supports '+configs.map(function(w){return L(w);}).join(' / ')+', but this build is front '+(frontSize?L(frontSize):'(any)')+' / rear '+(rearSize?L(rearSize):'(any)')+'.');
  }
  /* Frameless guard (REVIEW.md #18): with BOTH ends known and no frame picked,
     reject a pair that satisfies no config in the model - a reverse mullet
     (27.5 front / 29 rear) fits nothing in the model or in reality. A legit
     in-progress mullet (29 front / 27.5 rear) matches 'mullet' and stays
     silent - verified against every real config. */
  if(!frame && frontSize && rearSize){
    var anyCfg = Object.keys(WHEEL_CONFIG).some(function(cfg){ var c=WHEEL_CONFIG[cfg]; return frontSize===c.front && rearSize===c.rear; });
    if(!anyCfg) err('wheel-config', frontList.concat(rearList).map(function(s){ return s[2]; }), 'Unsupported wheel setup: front '+L(frontSize)+' / rear '+L(rearSize)+' matches no configuration (29/29, 27.5/27.5, or mullet = 29 front / 27.5 rear).');
  }

  /* 2. Axles */
  if(fork && fW && fork.axle!==fW.hub) err('front-axle', ['fork','frontWheel'], 'Front axle mismatch: Fork is '+L(fork.axle)+' but Front wheel hub is '+L(fW.hub)+'.');
  if(frame && rW && frame.rearAxle!==rW.hub) err('rear-axle', ['frame','rearWheel'], 'Rear axle mismatch: Frame is '+L(frame.rearAxle)+' but Rear wheel hub is '+L(rW.hub)+'.');

  /* 3. Drivetrain: one system + one speed. A SINGLE-SPEED chain (chainWidth,
        no system - 2026-07-13 DJ pass) carries no indexed-drivetrain identity,
        so it stays OUT of the one-system set: its real constraint is the
        ss-chain-width rule below, and counting it here would print an
        "undefined" system. Every geared chain has `system` (schema
        cross-rule), so live behavior is unchanged. */
  /** @type {Array<[string, DrivetrainPart]>} */
  var dt=[];
  if(shifter) dt.push(['Shifter',shifter]); if(derailleur) dt.push(['Derailleur',derailleur]);
  if(cassette) dt.push(['Cassette',cassette]); if(chain && chain.system) dt.push(['Chain',chain]);
  var dtSlots=dt.map(function(x){ return x[0].toLowerCase(); });   // slot keys happen to equal the lowercased labels
  if(dt.length>1){
    /* 3a AXS-controller exception (dossier rule 3 review, 2026-07-10): SRAM
          documents that ALL AXS controllers work with ALL AXS derailleurs -
          "you can use the new Eagle Transmission Pod Controllers with Eagle
          AXS Drivetrain, or the Eagle Drivetrain controller with Eagle
          Transmission" (support.sram.com articles 13820865674011 +
          13820000105371; browser-verified 2026-07-10 - the host is
          fetch-walled to tooling). An ELECTRONIC shifter in a SRAM AXS family
          is a protocol-level controller: exempt from the one-system set (its
          real constraint is 3b actuation). Mech/cassette/chain still must be
          one system, and the exemption does NOT cross to non-SRAM systems -
          a Pod driving a Shimano drivetrain stays an honest error. */
    var axsCtrl = !!(shifter && shifter.actuation==='electronic' && (shifter.system==='sram-eagle'||shifter.system==='sram-transmission'));
    var dtSys = axsCtrl ? dt.filter(function(x){ return x[1]!==shifter; }) : dt;
    var systems=dtSys.map(function(x){return x[1].system;}).filter(function(v,i,a){return a.indexOf(v)===i;});
    if(systems.length>1) err('drivetrain-system', dtSys.map(function(x){ return x[0].toLowerCase(); }), 'Drivetrain mismatch: '+dtSys.map(function(x){return x[0]+' = '+L(x[1].system||'');}).join(', ')+'. Shifter, derailleur, cassette and chain must be one system.');   // ||'': every dt entry has system (the chain guard above), the fallback only narrows the type
    else if(axsCtrl && systems.length===1 && systems[0]!=='sram-eagle' && systems[0]!=='sram-transmission')
      err('drivetrain-system', dtSlots, 'Drivetrain mismatch: '+dt.map(function(x){return x[0]+' = '+L(x[1].system||'');}).join(', ')+'. An AXS controller only drives SRAM AXS derailleurs.');
    /* Speed equality across the INDEXED parts only - shifter, derailleur,
          cassette. The CHAIN is deliberately excluded (engine-critical
          review M1, 2026-07-12): chains are WIDTH-defined, not speed-
          defined - SRAM's T-Type Flattop chain family spans both the 12s
          Transmission groups and the 7-speed XX Eagle Transmission DH
          group (CS-XS-797), so counting the chain forced a false speed
          red on a genuine SRAM-sold group and had been keeping that group
          out of the catalog (see the XX-DH omission note in the r3
          drivetrain batch comment). The chain's real constraint is its
          width FAMILY, which is exactly what `system` encodes - it stays
          in the one-system set above and in 3c. */
    var dtSpeed = dt.filter(function(x){ return x[1]!==chain; });
    var speeds=dtSpeed.map(function(x){return x[1].speeds;}).filter(function(v,i,a){return a.indexOf(v)===i;});
    if(speeds.length>1) err('drivetrain-speeds', dtSpeed.map(function(x){ return x[0].toLowerCase(); }), 'Speed mismatch: '+dtSpeed.map(function(x){return x[0]+' '+x[1].speeds+'s';}).join(', ')+'. Shifter, derailleur and cassette must be the same speed count.');
  }
  /* 3b. Actuation: a cable trigger cannot control a wireless (AXS) derailleur and
        an AXS controller cannot pull a cable - no adapter exists. Checked as its
        own field because `system` is genuinely shared across the divide (Eagle
        cassettes/chains fit both mechanical and AXS Eagle), so splitting the
        system vocab would false-red them (REVIEW.md #1). */
  if(shifter && derailleur && shifter.actuation!==derailleur.actuation)
    err('actuation', ['shifter','derailleur'], 'Actuation mismatch: '+nameOf(shifter)+' is '+L(shifter.actuation)+' but '+nameOf(derailleur)+' is '+L(derailleur.actuation)+'. A cable shifter cannot control a wireless derailleur (and vice versa).');
  /* 3c. Chainring standard: SRAM documents T-Type Flattop chains (unique link
        shape, pin size, larger rollers) as NOT compatible with non-T-Type rings.
        One-directional on purpose - T-Type rings ARE backward-compatible with
        Eagle chains, so the reverse must stay silent (REVIEW.md #2).
        ringStd:null = armset-only crank, ring user-fitted (eeWings, Race Face
        armsets): no ring to clash with, so it gets an INFO, not a false red. */
  if(chain && crankset && chain.system==='sram-transmission'){
    if(crankset.ringStd===null)
      info('chainring-standard', ['chain','crankset'], 'Chainring: '+nameOf(crankset)+' is sold without a chainring - fit a T-Type (8-bolt) ring to run the '+nameOf(chain)+'.');
    else if(!crankset.ringStd)   // ringStd ABSENT = the single-speed crank shape (chainWidth; 2026-07-13 DJ pass): its 1/8in-3/32in ring is by definition not a T-Type ring. Every live geared crank carries ringStd (schema cross-rule), so this branch is dormant for the live catalog.
      err('chainring-standard', ['chain','crankset'], 'Chainring mismatch: '+nameOf(chain)+' is a T-Type Flattop chain, but '+nameOf(crankset)+' runs a single-speed chainring. SRAM documents Flattop chains as incompatible with non-T-Type rings.');
    else if(crankset.ringStd!=='t-type')
      err('chainring-standard', ['chain','crankset'], 'Chainring mismatch: '+nameOf(chain)+' is a T-Type Flattop chain, but '+nameOf(crankset)+' has a '+L(crankset.ringStd)+' chainring. SRAM documents Flattop chains as incompatible with non-T-Type rings.');
  }

  /* 4. SRAM Transmission needs a UDH frame. Retrofit tier (dossier rule 4
        review, 2026-07-10 - "if a retrofit kit such as the RAAW is available,
        offer an info note or something, don't outright reject"): a frame with
        a maker-documented UDH retrofit kit (sourced udhRetrofitKit naming it)
        gets the rule-9 adapter-tier WARNING carrying the structured fix
        instead of the error - the frame as built cannot mount the mech, but
        the maker sells the conversion (RAAW UDH Retrofit Kit covers Jibb V1 /
        Madonna V2 / V2.2 - raawmtb.com/en-us/products/udh-retrofit-kit).
        Kit-less non-UDH frames stay a hard error; frameless info unchanged. */
  if(derailleur && derailleur.mount==='udh-direct'){
    if(frame && !frame.udh && typeof frame.udhRetrofitKit==='string')
      warn('udh', ['frame','derailleur'], 'Frame not UDH as built: '+nameOf(derailleur)+' is a direct-mount (UDH) Transmission derailleur and '+nameOf(frame)+' has a standard hanger - but the maker sells a retrofit kit ('+frame.udhRetrofitKit+') that converts the frame to UDH.', {kind:'adapter', name:frame.udhRetrofitKit});
    else if(frame && !frame.udh) err('udh', ['frame','derailleur'], 'Frame not UDH: '+nameOf(derailleur)+' is a direct-mount (UDH) Transmission derailleur, but '+nameOf(frame)+' has a standard hanger.');
    else if(!frame) info('udh', ['derailleur'], 'Heads-up: '+nameOf(derailleur)+' is a Transmission derailleur and needs a UDH / Transmission-compatible frame.');
  }

  /* 5. Cassette range vs derailleur capacity */
  if(cassette && derailleur && cassette.maxCog>derailleur.maxCog) err('cassette-capacity', ['cassette','derailleur'], 'Cassette too big: '+cassette.maxCog+'T cassette exceeds the '+nameOf(derailleur)+' max of '+derailleur.maxCog+'T.');

  /* 6. Freehub: cassette vs rear wheel. 6b (2026-07-10): freehub 'integrated'
        = the wheel's driver IS a built-in 7-speed (9-24T) cassette with no
        freehub body at all (e*thirteen LG1r DH - "Freehub Mount: Integrated
        7 Speed Cassette"), so ANY picked cassette is a hard error in its own
        words (nothing mounts; no adapter tier exists) - it replaces the
        generic mismatch, which would read as just another wrong-spline pick.
        With no cassette picked, an info marks the empty slot as by-design
        (slotRequired exempts it from completeness for the same reason). */
  if(cassette && rW && rW.freehub==='integrated')
    err('freehub-integrated', ['cassette','rearWheel'], 'Integrated cassette: Rear wheel has a built-in 7-speed (9-24T) cassette in place of a freehub body - '+nameOf(cassette)+' cannot mount, and no adapter exists.');
  else if(cassette && rW && cassette.freehub!==rW.freehub){
    /* 6c (2026-07-12, bias-audit finding #2): XD-on-XDR is DIRECTION-AWARE.
          SRAM's own driver-body explainer states "XDR driver bodies are
          compatible with all XD cassettes when the cassette is installed
          with a 1.85mm spacer behind it" (fetched sram.com/en/service/
          articles/sram-xd-and-xdr-driver-body-explained; XDR is the
          road-length XD driver, 1.85mm longer) -> the rule-9 adapter-tier
          warning carrying the spacer as a structured fix. The spacer fact is
          engine-side pair data, never a part field. Every other mismatch -
          including the reverse (an XDR-length cassette on a short XD driver;
          none cataloged today) - stays the exact-match hard error. */
    if(cassette.freehub==='XD' && rW.freehub==='XDR')
      warn('freehub', ['cassette','rearWheel'], 'Freehub: '+nameOf(cassette)+' is a SRAM XD cassette and Rear wheel has the road-length SRAM XDR driver - SRAM documents all XD cassettes fit an XDR driver with a 1.85mm spacer behind the cassette.', {kind:'adapter', name:'1.85mm XDR cassette spacer'});
    else
      err('freehub', ['cassette','rearWheel'], 'Freehub mismatch: '+nameOf(cassette)+' needs a '+L(cassette.freehub)+' freehub, but Rear wheel has '+L(/** @type {string} */ (rW.freehub))+'.');
  }
  if(!cassette && rW && rW.freehub==='integrated')
    info('freehub-integrated', ['rearWheel'], 'Integrated cassette: Rear wheel includes its own 7-speed (9-24T) cassette - no separate cassette is needed; the maker states it works with 10 and 11 speed chains from both Shimano and SRAM.');

  /* 6d. SINGLE-SPEED drivetrain (2026-07-13, Douglas's DJ/BMX architecture
        sign-off - data/DJ-BMX-COMPAT-ANALYSIS.md rules DJ-1 + DJ-2). Both
        rules land DORMANT for the live catalog: they read only the new
        single-speed fields (chainWidth on ring/cog/chain; driveMode +
        dropoutType on a frame), which no live part carries.
        ss-chain-width (DJ-1): the front ring, rear cog and chain of a
        single-speed drivetrain share a width class - 1/8in (BMX-derived) or
        3/32in (derailleur-width). Mixing them turns but runs poorly / wears
        fast, so this is a WARNING, not an error - PROVISIONAL severity per
        the analysis doc's Q6 lean, flagged for the mechanic review. The cog
        slot ships with the schema (no live GROUPS slot yet); the rule reads
        it now so the DJ go-live is a data flip, not an engine change. */
  /** @type {Array<[string, string, string]>} */ var ssw = [];   // [label, chainWidth, slotKey]
  if(crankset && crankset.chainWidth) ssw.push(['Crankset ring', crankset.chainWidth, 'crankset']);
  if(cog && cog.chainWidth) ssw.push(['Cog', cog.chainWidth, 'cog']);
  if(chain && chain.chainWidth) ssw.push(['Chain', chain.chainWidth, 'chain']);
  if(ssw.length>1){
    var sswWidths = ssw.map(function(x){ return x[1]; }).filter(function(v,i,a){ return a.indexOf(v)===i; });
    if(sswWidths.length>1)
      warn('ss-chain-width', ssw.map(function(x){ return x[2]; }),
        'Single-speed width mismatch: '+ssw.map(function(x){ return x[0]+' = '+x[1]+'in'; }).join(', ')+
        '. Ring, cog and chain should share one width class (1/8in or 3/32in) - a mixed stack turns but runs poorly and wears fast.');
  }
  /* ss-tension (DJ-2): a single-speed has no derailleur to take up chain
        slack. Horizontal / sliding dropouts and eccentric BBs tension by
        moving the wheel or BB; a VERTICAL dropout needs a chain tensioner or
        a half-link chain. INFO tier - it can always be made to work (three
        real solutions), so it nudges, never blocks. Fires only off a frame's
        sourced dropoutType; frames without the field stay silent. */
  if(frame && frame.driveMode==='single-speed' && frame.dropoutType==='vertical')
    info('ss-tension', ['frame'], 'Chain tension: '+nameOf(frame)+' has vertical dropouts and no derailleur to take up slack - single-speed setups here use a chain tensioner or a half-link chain to set tension.');

  /* 7. Crank / BB. With a real BB picked, both interfaces are exact checks
        (dossier rule 7 review 2026-07-10 - the BB category exists so
        servability is proven by purchasable rows instead of guessed):
        the BB's shell must match the frame, its spindle bore must match the
        crank. With no BB picked, the original sold-separately advisory
        stands (the bb slot is optional, never completeness-blocking).
        BSA68 <-> BSA73 EQUIVALENCE (engine-critical review C2, 2026-07-12):
        the two are the SAME threaded standard (English 1.37" x 24tpi) - a
        73mm shell simply omits the spacers a 68mm shell adds - and threaded
        BBs ship as ONE 68/73 SKU: the catalog's own bb-sram-dub-bsa68 and
        bb-sram-dub-bsa73 carry the identical mfgPn BB-DUB-BSA-A1, and Race
        Face sells "BSA CINCH ... (68/73)" by name. Exact-matching them
        hard-errored a physically correct build (a 68/73 BB on a BSA73
        frame) - a false "won't fit". BSA83 (the genuinely wider 83mm DH
        shell) and every press-fit/T47 shell stay exact-match. */
  /** @type {Object.<string, boolean>} */ var BSA_68_73 = { BSA68:true, BSA73:true };
  if(bb && frame && bb.shell!==frame.bb && !(BSA_68_73[bb.shell] && BSA_68_73[frame.bb]))
    err('bb-shell', ['bb','frame'], 'BB shell mismatch: '+nameOf(bb)+' fits a '+L(bb.shell)+' shell but '+nameOf(frame)+' has a '+L(frame.bb)+' shell.');
  if(bb && crankset && bb.spindle!==crankset.bb)
    err('bb-spindle', ['bb','crankset'], 'BB spindle mismatch: '+nameOf(bb)+' takes a '+L(bb.spindle)+' spindle but '+nameOf(crankset)+' is '+L(crankset.bb)+'.');
  if(!bb && crankset && frame) info('bb-advisory', ['crankset','frame'], 'Bottom bracket: '+nameOf(crankset)+' uses a '+L(crankset.bb)+' spindle - pair it with the right BB for this frame\'s '+L(frame.bb)+' shell (BB usually sold separately).');

  /* 8. Brake caliper mounts */
  if(fBrake && fork && fBrake.mount!==fork.brakeMount) err('front-brake-mount', ['frontBrake','fork'], 'Front brake mount mismatch: Brake is '+L(fBrake.mount)+' but Fork is '+L(fork.brakeMount)+'.');
  if(rBrake && frame && rBrake.mount!==frame.brakeMount) err('rear-brake-mount', ['rearBrake','frame'], 'Rear brake mount mismatch: Brake is '+L(rBrake.mount)+' but Frame is '+L(frame.brakeMount)+'.');
  /* 8b. CALIPER rotor ceiling (engine-critical review C1, 2026-07-12): a
        flat-mount caliper BODY has a hard rotor ceiling independent of the
        frame's mount rating - the FM system has no size-up bracket, so a
        frame whose FM mount allows 180 (rule 10's check) can still carry a
        caliper rated only to 160, and the build was going green. Maker
        statements only (rule-18 dormant-until-sourced template): Shimano's
        own caliper<->rotor compatibility chart C-461
        (productinfo.shimano.com/en/compatibility/C-461, fetched 2026-07-12)
        lists the BR-M9110 as "Not compatible with 220mm, 203 mm and 180 mm
        rotors" - 140/160 only. Post-mount calipers are size-agnostic (the
        MOUNT sets the limit, brackets take the caliper up any amount), so
        maxRotor stays ABSENT on them and the rule stays dormant - populating
        a PM caliper would create false reds. ERROR tier: the caliper
        genuinely cannot clear the rotor; no adapter exists. */
  if(fBrake && fRotor && typeof fBrake.maxRotor==='number' && fRotor.size>fBrake.maxRotor)
    err('front-brake-rotor-max', ['frontBrake','frontRotor'], 'Front rotor too big for the caliper: '+fRotor.size+'mm exceeds the '+nameOf(fBrake)+' caliper\'s maker-stated maximum of '+fBrake.maxRotor+'mm - the flat-mount system has no size-up bracket, so no adapter can make it fit.');
  if(rBrake && rRotor && typeof rBrake.maxRotor==='number' && rRotor.size>rBrake.maxRotor)
    err('rear-brake-rotor-max', ['rearBrake','rearRotor'], 'Rear rotor too big for the caliper: '+rRotor.size+'mm exceeds the '+nameOf(rBrake)+' caliper\'s maker-stated maximum of '+rBrake.maxRotor+'mm - the flat-mount system has no size-up bracket, so no adapter can make it fit.');

  /* 9. Rotor interface vs wheel hubs - DIRECTION-AWARE (REVIEW.md #10): a
        6-bolt rotor mounts on a Center Lock hub with the hub maker's own
        adapter (Shimano SM-RTAD05/RTAD10 - one-piece rotors only), an
        everyday shop fix -> warning carrying the adapter as a structured
        `fix` (the first use of the reserved adapter tier). The reverse -
        a Center Lock rotor on a 6-bolt hub - has no adapter -> error. */
  if(fRotor && fW && fRotor.mount!==fW.rotorMount){
    if(fRotor.mount==='sixbolt' && fW.rotorMount==='CL')
      warn('front-rotor-interface', ['frontRotor','frontWheel'], 'Front rotor: 6-bolt rotor on a Center Lock front hub needs a Center Lock adapter (e.g. Shimano SM-RTAD05; fits one-piece rotors only).', {kind:'adapter', name:'Shimano SM-RTAD05'});
    else
      err('front-rotor-interface', ['frontRotor','frontWheel'], 'Front rotor interface mismatch: '+L(fRotor.mount)+' rotor on '+L(fW.rotorMount)+' front hub - no adapter exists for this direction.');
  }
  if(rRotor && rW && rRotor.mount!==rW.rotorMount){
    if(rRotor.mount==='sixbolt' && rW.rotorMount==='CL')
      warn('rear-rotor-interface', ['rearRotor','rearWheel'], 'Rear rotor: 6-bolt rotor on a Center Lock rear hub needs a Center Lock adapter (e.g. Shimano SM-RTAD05; fits one-piece rotors only).', {kind:'adapter', name:'Shimano SM-RTAD05'});
    else
      err('rear-rotor-interface', ['rearRotor','rearWheel'], 'Rear rotor interface mismatch: '+L(rRotor.mount)+' rotor on '+L(rW.rotorMount)+' rear hub - no adapter exists for this direction.');
  }

  /* 10. Rotor size vs frame/fork max (warnings) - plus MINIMUM vs the fork's
        native mount (error). Post-mount adapters only space the caliper UP, so
        a rotor below the fork's native mount size is physically unmountable -
        no adapter exists. minRotorF is optional per the rule-18 dormant-until-
        sourced template: populated only from fetched manufacturer specs
        (REVIEW.md #3). */
  if(fRotor && fork && rotorOverMax(fRotor.size, fork.maxRotorF)) warn('front-rotor-max', ['frontRotor','fork'], 'Front rotor: '+fRotor.size+'mm exceeds the fork max of '+fork.maxRotorF+'mm.');
  if(rRotor && frame && rotorOverMax(rRotor.size, frame.maxRotorR)) warn('rear-rotor-max', ['rearRotor','frame'], 'Rear rotor: '+rRotor.size+'mm exceeds the frame max of '+frame.maxRotorR+'mm.');
  if(fRotor && fork && typeof fork.minRotorF==='number' && rotorUnderMin(fRotor.size, fork.minRotorF))
    err('front-rotor-min', ['frontRotor','fork'], 'Front rotor too small: '+fRotor.size+'mm is below the '+nameOf(fork)+' minimum of '+fork.minRotorF+'mm (its native mount size). Post-mount adapters only space the caliper up, so no adapter can make a smaller rotor fit.');
  /* 10b. FRAME-side native-mount rotor floor (dossier known-gaps verdict,
        2026-07-10: "use post-mount native size too") - the frame twin of
        front-rotor-min, dormant until a frame carries a maker-sourced
        minRotorR. First activation: Cotic Solaris, whose own page states
        "PM7 Post Mount (180mm rotor only)" - a 160 rotor physically cannot
        mount. Same physics: adapters only space the caliper UP. */
  if(rRotor && frame && typeof frame.minRotorR==='number' && rotorUnderMin(rRotor.size, frame.minRotorR))
    err('rear-rotor-min', ['rearRotor','frame'], 'Rear rotor too small: '+rRotor.size+'mm is below the '+nameOf(frame)+' minimum of '+frame.minRotorR+'mm (its native mount size). Post-mount adapters only space the caliper up, so no adapter can make a smaller rotor fit.');

  /* 11. Steerer / headset */
  if(fork && frame && fork.steerer!==frame.headset) err('steerer', ['fork','frame'], 'Steerer mismatch: Fork is '+L(fork.steerer)+' but Frame headset is '+L(frame.headset)+'.');

  /* 12. Fork travel vs frame rating - tiered by the SOURCE'S OWN LANGUAGE
        (engine-critical review C4, 2026-07-12, refining the 2026-07-10
        sourced-strict verdict). Fork travel is categorically unlike every
        other error in the engine: it never prevents assembly - any travel
        bolts to the head tube identically, and out-of-range travel only
        shifts BB height / head angle (~1° per 20mm) / warranty. So a hard
        ERROR is honest only where the maker states the range as a
        compatibility LIMIT (frame.forkTravelHard, set per-row from the
        cited source: Ibis "compatible with 150-170mm forks", Forbidden
        "160mm minimum up to 180mm maximum", HD6 "rated for 180-190 mm",
        Cotic "Minimum 100mm... Maximum 130mm"). Where the maker's own page
        explains its range as a RECOMMENDATION (all three Santa Cruz
        support pages, re-fetched 2026-07-12, FAQ verbatim: "We wouldn't
        recommend less travel than that, as the BB will get a bit low. Up
        to 180mm is fine if that's your preference"), out-of-range is a
        WARNING that says so - the old hard error asserted a "maker-approved
        minimum" those sources never state, a false "won't fit". Frames
        with no published range at all keep the softest tiers: over rated
        max = warning (~40 frames' maxForkTravel is still a permissive
        sample), >20mm under design = the 12c warning below. */
  var forkRange = !!(frame && typeof frame.minForkTravel==='number');
  var forkHard = !!(frame && frame.forkTravelHard===true);
  if(fork && frame && fork.travel>frame.maxForkTravel){
    if(forkRange && forkHard) err('fork-travel', ['fork','frame'], 'Fork travel: '+fork.travel+'mm is over '+nameOf(frame)+'\'s maker-stated compatibility range of '+frame.minForkTravel+'-'+frame.maxForkTravel+'mm.');
    else if(forkRange) warn('fork-travel', ['fork','frame'], 'Fork travel: '+fork.travel+'mm is over the '+frame.minForkTravel+'-'+frame.maxForkTravel+'mm range the maker recommends for '+nameOf(frame)+' - a recommendation, not a stated limit; it fits, but geometry and warranty are on you.');
    else warn('fork-travel', ['fork','frame'], 'Fork travel: '+fork.travel+'mm exceeds the frame\'s rated max of '+frame.maxForkTravel+'mm.');
  }
  /* 12b. UNDER-forking (REVIEW.md #14) - fires only when a frame carries a
        maker-published minForkTravel (~1 degree head-angle steepening per
        20mm). Sourced data only: a travel-based heuristic would false-fire
        on high-pivot frames (Dreadnought: 154mm travel, ships at 170).
        ERROR only under a maker-stated hard limit (forkTravelHard, C4);
        recommendation-language floors warn in the maker's own terms. */
  if(fork && frame && typeof frame.minForkTravel==='number' && fork.travel<frame.minForkTravel){
    if(forkHard)
      err('fork-travel-min', ['fork','frame'], 'Under-forked: '+fork.travel+'mm fork is below '+nameOf(frame)+'\'s maker-stated minimum of '+frame.minForkTravel+'mm - outside the stated compatibility range (steepens the geometry ~1° per 20mm).');
    else
      warn('fork-travel-min', ['fork','frame'], 'Under-forked: '+fork.travel+'mm fork is below the '+frame.minForkTravel+'mm minimum the maker recommends for '+nameOf(frame)+' - a recommendation, not a stated compatibility limit: it bolts on and works, but the BB drops and the head angle steepens ~1° per 20mm.');
  }
  /* 12c. DESIGN-travel under-fork (warning, 20mm grace) - dormant until a
        frame carries a maker-STATED designForkTravel ("geometry numbers are
        based around a 170mm travel fork"). This is design intent, NOT an
        approved floor (that is 12b/minForkTravel): more than 20mm below
        design steepens the head angle >1° and drops the BB well outside any
        common deliberate build, while 10-20mm under is a real custom choice
        and stays silent. Threshold flagged for the mechanic review.
        Suppressed when 12b already fired for the same pair (one verdict per
        conflict). Still manufacturer statements only - never derived from
        rear travel (the high-pivot false-fire, see 12b). */
  if(fork && frame && typeof frame.designForkTravel==='number' &&
     (frame.designForkTravel - fork.travel) > 20 &&
     !(typeof frame.minForkTravel==='number' && fork.travel<frame.minForkTravel))
    warn('fork-travel-design', ['fork','frame'], 'Under-forked: '+fork.travel+'mm fork is '+(frame.designForkTravel-fork.travel)+'mm below the '+frame.designForkTravel+'mm fork this frame\'s geometry is designed around (maker-stated) - steepens the head angle ~1° per 20mm and lowers the bottom bracket.');

  /* 13. Dropper diameter vs seat tube - DIRECTION-AWARE (REVIEW.md #9): a
        bigger post in a smaller tube is physically impossible (error); a
        smaller post in a bigger tube is a common, shop-approved build with a
        reducing shim (Problem Solvers / Wolf Tooth; PNW's own sizing guide
        endorses shimming) -> warning naming the shim, not a false red. */
  if(dropper && frame){
    if(dropper.diameter>frame.seatTube){
      err('dropper-diameter', ['dropper','frame'], 'Dropper too big: Frame seat tube is '+frame.seatTube+'mm but Dropper is '+dropper.diameter+'mm - a bigger post cannot fit a smaller tube.');
    } else if(dropper.diameter<frame.seatTube){
      warn('dropper-shim', ['dropper','frame'], 'Dropper shim needed: a '+dropper.diameter+'mm post in a '+frame.seatTube+'mm seat tube works with a '+frame.seatTube+'-to-'+dropper.diameter+'mm reducing shim (sold separately).');
    }
    /* 13b. Insertion depth (REVIEW.md #23, near-term tier): fit for long-drop
          posts is decided by post length vs per-size usable insertion, and the
          app has no frame-size concept yet - so a >=200mm drop gets an INFO
          nudge, never a verdict. The real check needs frame.sizes.maxInsert +
          a size picker (deferred with the frameSize share-hash key). */
    if(dropper.drop>=180)   /* threshold 200->180 per the dossier rule 13 review verdict (2026-07-10) */
      info('dropper-insertion', ['dropper','frame'], 'Long-drop post: the '+nameOf(dropper)+' ('+dropper.drop+'mm) needs deep seat-tube insertion - check the maker\'s insertion calculator for your '+nameOf(frame)+' frame size.');
  }

  /* 13c. Rigid seatpost diameter vs seat tube (DJ go-live, 2026-07-14) - the
        seatpost slot's twin of rule 13, same direction-aware physics and the
        same shim doctrine: bigger post in a smaller tube = impossible (error);
        smaller post in a bigger tube = works with a reducing shim (warning).
        The slot is brand new, so no pre-existing build or share link can carry
        it - live verdicts are unchanged by construction. */
  if(seatpost && frame){
    if(seatpost.diameter>frame.seatTube){
      err('seatpost-diameter', ['seatpost','frame'], 'Seatpost too big: Frame seat tube is '+frame.seatTube+'mm but Seatpost is '+seatpost.diameter+'mm - a bigger post cannot fit a smaller tube.');
    } else if(seatpost.diameter<frame.seatTube){
      warn('seatpost-shim', ['seatpost','frame'], 'Seatpost shim needed: a '+seatpost.diameter+'mm post in a '+frame.seatTube+'mm seat tube works with a '+frame.seatTube+'-to-'+seatpost.diameter+'mm reducing shim (sold separately).');
    }
  }

  /* 14. Tire width vs wheel clearance (per wheel, warnings) */
  if(fTire && fW && fTire.width>fW.maxTire) warn('front-tire-rim', ['frontTire','frontWheel'], 'Front tire clearance: '+fTire.width+'in tire is wider than the front wheel\'s '+fW.maxTire+'in max.');
  if(rTire && rW && rTire.width>rW.maxTire) warn('rear-tire-rim', ['rearTire','rearWheel'], 'Rear tire clearance: '+rTire.width+'in tire is wider than the rear wheel\'s '+rW.maxTire+'in max.');
  /* 14c. Too-NARROW tire on a wide rim (dossier rule 14 review verdict,
        2026-07-10: "put a soft warning if the tire width is out of range on
        what the rim recommends") - dormant until a wheel/rim carries a
        maker-published minTire (maker recommendations only, never an
        ETRTO-derived guess - the dossier records those thresholds as fuzzy).
        Soft warning: the tire mounts, but squares off / loses bead support. */
  if(fTire && fW && typeof fW.minTire==='number' && fTire.width<fW.minTire)
    warn('front-tire-rim-min', ['frontTire','frontWheel'], 'Front tire width: '+fTire.width+'in is below the wheel maker\'s recommended minimum of '+fW.minTire+'in for this rim - a too-narrow tire squares off and loses bead support on a wide rim.');
  if(rTire && rW && typeof rW.minTire==='number' && rTire.width<rW.minTire)
    warn('rear-tire-rim-min', ['rearTire','rearWheel'], 'Rear tire width: '+rTire.width+'in is below the wheel maker\'s recommended minimum of '+rW.minTire+'in for this rim - a too-narrow tire squares off and loses bead support on a wide rim.');
  /* 14b. Front tire vs FORK crown/arch clearance (REVIEW.md #22) - the
        fork-side twin of rule 18, dormant until a fork carries a
        maker-published maxTire (Fox/RockShox publish per chassis). */
  if(fTire && fork && typeof fork.maxTire==='number' && fTire.width>fork.maxTire)
    warn('front-tire-fork', ['frontTire','fork'], 'Front tire clearance: '+fTire.width+'in tire is wider than '+nameOf(fork)+'\'s '+fork.maxTire+'in chassis max.');

  /* 15. Handlebar / stem clamp - DIRECTION-AWARE (engine-critical review C3,
        2026-07-12; the same asymmetry REVIEW.md #9 fixed on the dropper,
        rule 13): a bar whose clamp area is BIGGER than the stem's bore is
        physically impossible (error), but a SMALLER bar in a bigger stem is
        an everyday stocked-shim build - handlebar reducer shims are a
        maker-sold category (Reverse Components Ø35.0->31.8: "combine a
        31.8 mm handlebar with a 35.0 mm oversize stem"; Wheels Mfg;
        Problem Solvers; FARR) -> warning naming the shim, carried as a
        structured fix (the rotor-adapter/UDH-kit tier). The old
        symmetric hard error was a false "won't fit" on the shim
        direction. */
  if(bar && stem && bar.clamp!==stem.clamp){
    if(bar.clamp>stem.clamp)
      err('bar-stem-clamp', ['handlebar','stem'], 'Bar/stem clamp mismatch: Handlebar is '+bar.clamp+'mm but Stem is '+stem.clamp+'mm - a bigger bar cannot fit a smaller stem clamp.');
    else
      warn('bar-stem-shim', ['handlebar','stem'], 'Stem shim needed: a '+bar.clamp+'mm bar in a '+stem.clamp+'mm stem works with a '+stem.clamp+'-to-'+bar.clamp+'mm handlebar reducer shim (sold separately - Wheels Mfg / Problem Solvers / Reverse Components).', {kind:'shim', name:stem.clamp+'-to-'+bar.clamp+'mm handlebar reducer shim'});
  }

  /* 16. Rear shock physical fit vs frame. Hardtails carry NO shock block
        (schema cross-rule), so they get their own message instead of a
        nonsense "needs undefinedxundefined" comparison.
        Stroke is DIRECTION-AWARE (REVIEW.md #8): physical fit is set by
        eye-to-eye + mount. A LONGER stroke over-rotates the linkage /
        bottoms the shock on the frame -> error. A SHORTER stroke with
        matching eye+mount sweeps a strict subset of the designed range -
        makers sell the same body in several strokes and RockShox supports
        stroke-spacer reduction - so it bolts in with less travel: warning,
        quantified, not a false red. */
  if(shock && frame){
    if(frame.suspension==='hardtail'){
      err('hardtail-shock', ['shock','frame'], 'Hardtail: '+nameOf(frame)+' has no rear-shock mount - remove the '+nameOf(shock)+'.');
    } else {
      if(shock.eye!==frame.shockEye){
        err('shock-size', ['shock','frame'], 'Shock size mismatch: Frame needs '+frame.shockEye+'x'+frame.shockStroke+'mm but Shock is '+shock.eye+'x'+shock.stroke+'mm.');
      } else if(shock.stroke>frame.shockStroke){
        err('shock-stroke-over', ['shock','frame'], 'Shock stroke too long: '+nameOf(shock)+' is '+shock.eye+'x'+shock.stroke+'mm but '+nameOf(frame)+' is designed for '+frame.shockEye+'x'+frame.shockStroke+'mm - the extra stroke can over-rotate the linkage or bottom the shock on the frame.');
      } else if(shock.stroke<frame.shockStroke){
        /* No estimated travel figure (dossier rule 16 review verdict,
           2026-07-10: "don't estimate the travel, find out what travel the
           frames ship with") - a linear frame.travel*stroke ratio is wrong on
           progressive linkages. Quantify only from maker-stated reduced-travel
           figures when a frame carries them (future sourced data, e.g.
           Transition publishes "170mm rear, 160 w/ a 205x60 shock"). */
        warn('shock-stroke-short', ['shock','frame'], 'Shorter-stroke shock: '+shock.eye+'x'+shock.stroke+'mm in a '+frame.shockEye+'x'+frame.shockStroke+'mm frame bolts in (same eye-to-eye) but reduces rear travel below the frame\'s designed '+frame.travel+'mm - check the frame maker\'s supported strokes and bottom-out clearance.');
      }
      if(shock.mount!==frame.shockMount) err('shock-mount', ['shock','frame'], 'Shock mount mismatch: Frame uses a '+L(frame.shockMount)+' shock but Shock is '+L(shock.mount)+'.');
      /* 16b. Coil approval (REVIEW.md #21) - dormant until a frame carries a
            maker STATEMENT (coilApproved:false, e.g. Ibis's "leverage ratio
            ... not coil-compatible"). Never inferred from leverage curves;
            absence of the field means unknown, and unknown stays silent. */
      if(frame.coilApproved===false && shock.spring==='coil')
        warn('coil-approval', ['shock','frame'], 'Coil shock: '+nameOf(frame)+'\'s maker states this frame is not coil-compatible (leverage curve) - the '+nameOf(shock)+' is a coil.');
    }
  }

  /* 17. Frame + shock bundling (only full-sus frames bundle - the schema
        forbids bundledShock on hardtails) */
  if(frame && frame.suspension==='full' && frame.bundledShock){
    var inc = byId(frame.bundledShock), incName = nameOf(inc);
    if(!shock){ info('bundled-shock', ['frame'], 'Frame package: '+nameOf(frame)+' is sold as a frame+shock'+(frame.frameOnly?' (frame-only also available)':' package only')+' with the '+incName+'. Add it under Rear Shock, or pick another.'); }
    else if(shock.id===frame.bundledShock){ info('bundled-shock', ['frame','shock'], 'Package match: you are using the '+incName+' that '+nameOf(frame)+' ships with.'); }
    else if(frame.frameOnly===false){ warn('package-only', ['frame','shock'], 'Frame is package-only: '+nameOf(frame)+' is sold only as a frame+shock bundle with the '+incName+'. You can run the '+nameOf(shock)+', but you will still have to buy the bundle (and pay for the '+incName+') since the frame is not sold bare.'); }
    else { info('bundled-shock', ['frame','shock'], 'Note: '+nameOf(frame)+' ships with the '+incName+', but is also sold frame-only - running the '+nameOf(shock)+' is fine.'); }
  }
  if(shock && shock.oemOnly){
    var hostIds = shock.forFrames || [];
    var hostNames = hostIds.map(function(id){ return nameOf(byId(id)); }).join(' / ');
    /* Frameless case downgrades to info, mirroring rule 4's convention (a
       Transmission derailleur with no frame is an info, not a red) - the
       build isn't wrong yet, it just needs the right frame (REVIEW.md #17). */
    if(!frame){
      info('oem-shock', ['shock'], 'Heads-up: the '+nameOf(shock)+' is OEM-only - it ships with the '+hostNames+' and is not sold separately, so plan on that frame.');
    } else if(hostIds.indexOf(frame.id)<0){
      err('oem-shock', ['shock','frame'], 'OEM shock: the '+nameOf(shock)+' is only available bundled with the '+hostNames+' - it is not sold separately.');
    }
  }

  /* 18. Rear tire vs FRAME clearance (optional frame.maxTire, warning). The
        frame/swingarm complement to rule 14's rim-clearance check. Fires only
        where a frame carries a manufacturer-sourced maxTire (10 catalog frames
        as of 2026-07-06); frames without published clearance stay silent -
        a missing rule beats a wrong one. */
  if(rTire && frame && typeof frame.maxTire==='number' && rTire.width>frame.maxTire)
    warn('rear-tire-frame', ['rearTire','frame'], 'Rear tire clearance: '+rTire.width+'in tire is wider than '+nameOf(frame)+'\'s '+frame.maxTire+'in frame max.');

  /* 19. Shifter mounting vs brake lever integration (optional fields - dormant
        until parts carry them, per the rule-18 template). A lever-integrated
        shifter (I-Spec EV/II/B, MatchMaker) ships with NO handlebar clamp of
        its own and only bolts to a lever that accepts its standard - the
        I-Spec generations are mutually incompatible. A lever may accept
        SEVERAL standards via the maker's own clamps (leverAccepts is an
        array). Warning, not error: band-clamp SKUs and ShiftMount-style
        adapters exist (REVIEW.md #5). One matching lever is enough - the
        shifter pairs with that side. */
  var LEVER_INTEGRATED = ['ispec-ev','ispec-ii','ispec-b','matchmaker'];
  if(shifter && shifter.clampType && LEVER_INTEGRATED.indexOf(shifter.clampType)>=0){
    var sClamp = shifter.clampType;
    /** @type {string[]} */ var lClamps = [];
    /** @type {string[]} */ var lSlots = ['shifter'];
    [[fBrake,'frontBrake'], [rBrake,'rearBrake']].forEach(function(pair){
      var bk = /** @type {import('./types.js').BrakePart|undefined} */ (pair[0]);
      if(bk && bk.leverAccepts){ lClamps = lClamps.concat(bk.leverAccepts); lSlots.push(/** @type {string} */ (pair[1])); }
    });
    if(lClamps.length && lClamps.indexOf(sClamp)<0){
      var uniq = lClamps.filter(function(v,i,a){ return a.indexOf(v)===i; }).map(function(c){ return L(c); }).join(' / ');
      warn('shifter-mount', lSlots, 'Shifter mount: '+nameOf(shifter)+' is a '+L(sClamp)+' lever-integrated shifter (no bar clamp of its own), but the brake levers take '+uniq+'. You need the band-clamp version or a ShiftMount-style adapter to mount it.');
    }
  }

  /* 20. Headset (headset-category pass, 2026-07-10; rule 7/BB is the template).
        20a - steerer acceptance vs the fork, ACTIVE: exact equality, the same
        semantics as rule 11 (which keeps consuming frame.headset for the
        no-headset-picked path; its documented crown-race-reducer softening
        stays THE expert-review question for both). 20b - cup vs head tube,
        rule-18 dormant-until-sourced template: fires only where a frame
        carries a fetched headTubeUpper/headTubeLower (51 frames at landing),
        and compares S.H.I.S. BORE TOKENS only (see shisBore - the suffix is
        steerer business, and the backfill's suffixes assume tapered
        assemblies). Cup-in-bore is press-fit exact: a 44mm cup rattles in a
        56mm bore, a 56 cannot press into a 44, an IS bearing has no seat in a
        ZS tube - so a bore mismatch is an ERROR, no adapter tier exists.
        20c - advisory info once frame+fork are picked: unlike BBs, frames
        OFTEN ship with a headset, so the wording nudges a check instead of
        claiming sold-separately. */
  if(hset && fork && hset.steerer!==fork.steerer)
    err('headset-steerer', ['headset','fork'], 'Headset steerer mismatch: '+nameOf(hset)+' accepts a '+L(hset.steerer)+' steerer but '+nameOf(fork)+' is '+L(fork.steerer)+'.');
  if(hset && frame && typeof frame.headTubeUpper==='string' && shisBore(hset.upper)!==shisBore(frame.headTubeUpper))
    err('headset-upper', ['headset','frame'], 'Headset upper cup mismatch: '+nameOf(hset)+' upper is '+hset.upper+' but '+nameOf(frame)+'\'s upper head tube is '+shisBore(frame.headTubeUpper)+' (S.H.I.S.) - cups press in at their exact bore only.');
  if(hset && frame && typeof frame.headTubeLower==='string' && shisBore(hset.lower)!==shisBore(frame.headTubeLower))
    err('headset-lower', ['headset','frame'], 'Headset lower cup mismatch: '+nameOf(hset)+' lower is '+hset.lower+' but '+nameOf(frame)+'\'s lower head tube is '+shisBore(frame.headTubeLower)+' (S.H.I.S.) - cups press in at their exact bore only.');
  if(!hset && frame && fork){
    if(typeof frame.headTubeUpper==='string' && typeof frame.headTubeLower==='string')
      info('headset-advisory', ['frame','fork'], 'Headset: '+nameOf(frame)+' takes '+shisBore(frame.headTubeUpper)+' upper / '+shisBore(frame.headTubeLower)+' lower cups (S.H.I.S.) to mount the fork - many frames ship with one; pick one here if yours does not.');
    else
      info('headset-advisory', ['frame','fork'], 'Headset: mounting the '+nameOf(fork)+' in '+nameOf(frame)+' needs a headset - many frames ship with one; pick one here if yours does not.');
  }

  return { errors:errors, warnings:warnings, infos:infos };
}

/* =============================================================================
   COMPATIBILITY HELPERS (shared by the UI and the test suite)
   build is a map of slotKey -> resolved part object.
   ========================================================================== */
/** @type {Object.<string, string[]>|null} */
var _CAT_SLOTS = null;
/** @returns {Object.<string, string[]>} */
function _catSlots(){
  if(!_CAT_SLOTS){
    /** @type {Object.<string, string[]>} */ var acc = {};
    SLOTS.forEach(function(s){ (acc[s.cat]=acc[s.cat]||[]).push(s.key); });
    _CAT_SLOTS = acc;
  }
  return _CAT_SLOTS;
}
/** Diff one placement of a part into a slot: the first NEW error and the first
 * NEW warning it introduces (null = none of that class). Diffs by verdictKey
 * (ruleId+slots+msg), NOT message text: two different conflicts can raise
 * byte-identical strings (REVIEW.md #4/#13's maskings).
 * @param {Part} part @param {string} slotKey @param {Build} [build]
 * @returns {{error: (string|null), warning: (string|null)}} */
function placementDiff(part, slotKey, build){
  /** @type {Build} */ var base = Object.assign({}, build || {}); delete base[slotKey];
  var before = checkBuild(base);
  var beforeE = before.errors.map(verdictKey), beforeW = before.warnings.map(verdictKey);
  /** @type {Build} */ var test = Object.assign({}, base); test[slotKey] = part;
  var after = checkBuild(test);
  /** @type {string|null} */ var e = null;
  /** @type {string|null} */ var w = null;
  for(var i=0;i<after.errors.length;i++){ if(beforeE.indexOf(verdictKey(after.errors[i]))<0){ e = String(after.errors[i]); break; } }
  for(var j=0;j<after.warnings.length;j++){ if(beforeW.indexOf(verdictKey(after.warnings[j]))<0){ w = String(after.warnings[j]); break; } }
  return { error:e, warning:w };
}
/** First NEW error this placement introduces (errors only - the dot goes
 * through placementDiff so new WARNINGS surface as yellow too, REVIEW.md #6).
 * @param {Part} part @param {string} slotKey @param {Build} [build] @returns {string|null} */
function conflictReason(part, slotKey, build){ return placementDiff(part, slotKey, build).error; }
/** @param {Part} p @param {Build} [build] @returns {CompatState} */
function compatOf(p, build){
  /** @type {Build} */ var bld = build || {};
  if(Object.keys(bld).length===0) return {state:'n', reason:'Pick some parts first to check fit'};
  if('fills' in p && p.fills){
    var pf = p.fills;
    // Baseline = the build with every slot the preset fills CLEARED first
    // (mirrors the single-part path, where placementDiff deletes the tested
    // slot). Diffing against the un-cleared build let a pre-existing error
    // string mask the preset's own byte-identical conflict -> false green on
    // exactly the kits a user browses to FIX a misfit (REVIEW.md #4).
    /** @type {Build} */ var base = Object.assign({}, bld);
    Object.keys(pf).forEach(function(s){ delete base[s]; });
    var before = checkBuild(base);
    var beforeE = before.errors.map(verdictKey), beforeW = before.warnings.map(verdictKey);
    /** @type {Build} */ var test = Object.assign({}, base);
    Object.keys(pf).forEach(function(s){ test[s]=/** @type {Part} */(byId(pf[s])); });
    var after = checkBuild(test);
    // Red if applying the preset INTRODUCES a conflict - detected by new-verdict
    // set membership (verdictKey, not message text and not error count), so a
    // preset that swaps one conflict for another still shows red.
    var extra = after.errors.filter(function(e){ return beforeE.indexOf(verdictKey(e))<0; });
    if(extra.length){ return {state:'r', reason:String(extra[0])}; }
    // Yellow if it introduces no error but >=1 new warning: warning-class
    // misfits (over-max rotor, over-travel fork...) used to render as green
    // "fits" at pick time and only flag AFTER being added (REVIEW.md #6).
    var extraW = after.warnings.filter(function(w){ return beforeW.indexOf(verdictKey(w))<0; });
    if(extraW.length){ return {state:'w', reason:String(extraW[0])}; }
    return {state:'g', reason:'No conflicts with your current build'};
  }
  var slots = _catSlots()[p.cat] || [];
  /** @type {string|null} */ var firstErr = null;
  /** @type {string|null} */ var firstWarn = null;
  for(var i=0;i<slots.length;i++){
    var d = placementDiff(p, slots[i], bld);
    if(!d.error && !d.warning) return {state:'g', reason:'No conflicts with your current build'};
    if(!d.error){ if(firstWarn===null) firstWarn = d.warning; }
    else if(firstErr===null){ firstErr = d.error; }
  }
  // A part that fits SOME slot with only a warning outranks one that errors
  // everywhere (multi-slot cats - tires/brakes/rotors - dot their best slot).
  if(firstWarn!==null) return {state:'w', reason:firstWarn};
  return {state:'r', reason:(firstErr||'Conflicts with your current build')};
}

/* =============================================================================
   PRICING + WEIGHT
   A group whose slots exactly match a chosen preset is billed/weighed as the
   bundle; otherwise its parts are summed individually.
   ========================================================================== */
/** @param {Group} group @param {Build} build @param {PresetBy} [presetBy] @returns {boolean} */
function bundleActive(group, build, presetBy){
  var pid = presetBy && presetBy[group.key];
  if(!pid) return false;
  var preset = byId(pid);
  if(!preset || !('fills' in preset) || !preset.fills) return false;
  // The preset must BELONG to this group (REVIEW.md #25): without this check a
  // crafted/corrupted share link could bill the wheels group as a $545
  // groupset, double-count the drivetrain and never count the wheels -
  // silently corrupting the headline totals. readHash is hardened the same way.
  if(!group.preset || preset.cat !== group.preset.cat) return false;
  var fills = preset.fills;
  var slots = Object.keys(fills);
  for(var i=0;i<slots.length;i++){
    var chosen = build[slots[i]];
    if(!chosen || chosen.id !== fills[slots[i]]) return false;
  }
  return true;
}
/** @param {Build} [build] @param {PresetBy} [presetBy] @returns {Totals} */
function buildTotals(build, presetBy){
  build = resolveBuild(build); presetBy = presetBy || {};
  var price = 0, weight = 0, missingWeight = false;
  GROUPS.forEach(function(g){
    if(g.preset && bundleActive(g, build, presetBy)){
      var preset = byId(presetBy[g.key]);
      if(preset){
        price += (preset.price || 0);
        // bundle weight is DERIVED from the fills - kits never store a weight
        // (a stored figure drifts into impossible bundles, REVIEW.md #12)
        var pw = partWeight(preset);
        if(pw != null) weight += pw; else missingWeight = true;
      }
    } else {
      g.slots.forEach(function(s){
        var p = build[s.key];
        if(p){
          price += (typeof p.price === 'number' ? p.price : 0);
          if(typeof p.weight === 'number') weight += p.weight; else missingWeight = true;
        }
      });
    }
  });
  return { price:price, weight:weight, missingWeight:missingWeight };
}

/* =============================================================================
   RANDOM SAMPLE BUILDS
   The toolbar's sample-build buttons generate a FRESH random build within a
   theme on every click, rather than loading a fixed one. The invariant that
   keeps them honest (they exist to showcase the checker): a generated build is
   ALWAYS complete per slotRequired() and has ZERO checkBuild errors - warnings
   are tolerated, but a candidate that adds none is preferred at every slot.
   The generator CONSUMES checkBuild/slotRequired; it never encodes a fit rule
   of its own, so it can never disagree with the engine. The RNG is injectable
   (tests seed it for determinism); the UI passes Math.random.
   ========================================================================== */

/** A small seedable PRNG (mulberry32): deterministic given a seed, so the
 * property test can assert same-seed-same-build and the UI can reproduce a
 * build from a seed if ever needed. @param {number} seed @returns {function(): number} */
function mulberry32(seed){
  var a = seed >>> 0;
  return function(){
    a |= 0; a = (a + 0x6D2B79F5) | 0;
    var t = Math.imul(a ^ (a >>> 15), 1 | a);
    t = (t + Math.imul(t ^ (t >>> 7), 61 | t)) ^ t;
    return ((t ^ (t >>> 14)) >>> 0) / 4294967296;
  };
}

/** Uniform in-place Fisher-Yates shuffle. `arr.sort(() => Math.random() - 0.5)`
 * is NOT uniform (comparator-sort shuffles are engine-dependent and biased
 * toward certain orderings), which would quietly reintroduce the exact
 * catalog-ordering bias this exists to remove. Returns the same array
 * (mutated) for convenient chaining. `rng` defaults to Math.random; pass a
 * seeded generator (e.g. mulberry32) for deterministic tests.
 * @template T @param {T[]} arr @param {function(): number} [rng] @returns {T[]} */
function fisherYatesShuffle(arr, rng){
  var rand = rng || Math.random;
  for(var i = arr.length - 1; i > 0; i--){
    var j = Math.floor(rand() * (i + 1));
    var tmp = arr[i]; arr[i] = arr[j]; arr[j] = tmp;
  }
  return arr;
}

/** Fill order: every slot's constraints depend only on slots earlier in the
 * list - frame first; wheels before the cassette that must match the rear
 * freehub and before the tires/rotors that read wheel size & mount; frame+fork
 * before the brakes/rotors that check their mounts and max sizes. Greedy in
 * this order lets each pick filter against everything already chosen. Frame is
 * handled first, separately (its pool is the themed frame set). @type {string[]} */
var _SAMPLE_PLAN = ['fork','frontWheel','rearWheel','shock','frontTire','rearTire',
  'shifter','derailleur','cassette','chain','crankset',
  'frontBrake','rearBrake','frontRotor','rearRotor',
  'bb','headset','dropper','handlebar','stem','grips','saddle','pedals'];

/** The sample-build themes, keyed to the toolbar buttons. @type {SampleTheme[]} */
var SAMPLE_THEMES = [
  /* The three price bands exclude dj-discipline frames (DJ go-live, 2026-07-14):
     a theme-scope choice like the dh/trail/xc filters below, NOT a fit rule.
     DJ frames are cheap enough to dominate the Budget band, but the generator's
     plan is a geared-MTB showcase - on a single-speed frame it would ship no
     cog/seatpost (incomplete), and on a geared-convertible 26" frame the only
     26" rear wheel is a single-speed driver, making shifter+derailleur picks
     read as a fake geared build. A dedicated DJ sample theme can join later. */
  { key:'budget', label:'Budget',    band:{p:0.12, w:0.18}, frame:function(f){ return (f.disciplines||[]).indexOf('dj')<0; } },
  { key:'mid',    label:'Mid-range', band:{p:0.50, w:0.20}, frame:function(f){ return (f.disciplines||[]).indexOf('dj')<0; } },
  { key:'high',   label:'High-end',  band:{p:0.90, w:0.15}, frame:function(f){ return (f.disciplines||[]).indexOf('dj')<0; } },
  { key:'mullet', label:'Mullet',    band:null, mullet:true, frame:function(f){ return (f.wheelConfigs||[]).indexOf('mullet')>=0; } },
  { key:'dh',     label:'DH',        band:null, frame:function(f){ return (f.disciplines||[]).indexOf('dh')>=0; } },
  { key:'trail',  label:'Trail',     band:null, frame:function(f){ return (f.disciplines||[]).indexOf('trail')>=0; } },
  { key:'xc',     label:'XC',        band:null, frame:function(f){ return (f.disciplines||[]).indexOf('xc')>=0; } },
  /* Hardtail: any suspension:'hardtail' frame outside the DJ/single-speed set -
     those frames drop the whole geared drivetrain plan (shifter/derailleur/
     cassette) for a cog, which _SAMPLE_PLAN doesn't fill; a dedicated DJ theme
     can join later like the band themes' own dj exclusion above. slotRequired()
     already exempts the shock slot for a hardtail frame, so the shared
     _SAMPLE_PLAN naturally produces a no-shock build with no extra logic here. */
  { key:'hardtail', label:'Hardtail', band:null, frame:function(f){ return f.suspension==='hardtail' && (f.disciplines||[]).indexOf('dj')<0 && f.driveMode!=='single-speed'; } }
];

/** PARTS grouped by category (memoized - the catalog is immutable at runtime). @type {Object.<string, Part[]>|null} */
var _PARTS_BY_CAT = null;
/** @param {string} cat @returns {Part[]} */
function _partsByCat(cat){
  if(!_PARTS_BY_CAT){
    _PARTS_BY_CAT = {};
    for(var i=0;i<PARTS.length;i++){ var c = PARTS[i].cat; (_PARTS_BY_CAT[c] = _PARTS_BY_CAT[c] || []).push(PARTS[i]); }
  }
  return _PARTS_BY_CAT[cat] || [];
}

/** Pick from a list, biasing toward a price percentile band (null = uniform).
 * Sorts ascending by price and samples an index in [p-w, p+w] (clamped to
 * [0,1]), so Budget lands in the cheap tail and High-end in the dear tail while
 * staying random. @param {Part[]} list @param {{p:number,w:number}|null} band @param {function():number} rng @returns {Part|null} */
function _bandPick(list, band, rng){
  if(!list.length) return null;
  if(!band) return list[Math.floor(rng() * list.length)];
  var sorted = list.slice().sort(function(a,b){ return (a.price||0) - (b.price||0); });
  var n = sorted.length;
  var lo = Math.max(0, band.p - band.w), hi = Math.min(1, band.p + band.w);
  var idx = Math.round((lo + rng() * (hi - lo)) * (n - 1));
  return sorted[idx];
}

/** Mullet wheel-size gate: front-side slots must be 29, rear-side 27.5. Other
 * themes take whatever the frame's wheelConfigs allow (the engine enforces it).
 * @param {SampleTheme} theme @param {string} slotKey @param {Part} part @returns {boolean} */
function _mulletWheelOK(theme, slotKey, part){
  if(!theme.mullet) return true;
  var w = /** @type {any} */(part).wheel;
  if(slotKey==='fork' || slotKey==='frontWheel' || slotKey==='frontTire') return w === '29';
  if(slotKey==='rearWheel' || slotKey==='rearTire') return w === '275';
  return true;
}

/* key -> slot index, memoized like _BY_ID (SLOTS is immutable at runtime).
   Both sample-build lookups below used to linear-scan SLOTS per call. */
/** @type {Object.<string, Slot>|null} */
var _SLOT_BY_KEY = null;
/** @param {string} key @returns {Slot|null} */
function _slotByKey(key){
  if(!_SLOT_BY_KEY){
    /** @type {Object.<string, Slot>} */ var acc = Object.create(null);
    for(var i=0;i<SLOTS.length;i++){ acc[SLOTS[i].key] = SLOTS[i]; }
    _SLOT_BY_KEY = acc;
  }
  return (key && _SLOT_BY_KEY[key]) || null;
}

/** Choose a part for one slot against the partial build: keep only candidates
 * that introduce NO new checkBuild error, prefer those that also add no new
 * warning, then band-sample. The baseline verdict sets are computed once per
 * slot (not per candidate). Mirrors placementDiff's verdictKey diffing exactly
 * - it just does it in bulk. Returns null when nothing fits (caller retries).
 * @param {Build} build @param {string} slotKey @param {SampleTheme} theme @param {function():number} rng @returns {Part|null} */
function _sampleSlotPick(build, slotKey, theme, rng){
  var slot = _slotByKey(slotKey);
  if(!slot) return null;
  /** @type {Build} */ var base = Object.assign({}, build); delete base[slotKey];
  var before = checkBuild(base);
  var beforeE = before.errors.map(verdictKey), beforeW = before.warnings.map(verdictKey);
  var cands = _partsByCat(slot.cat);
  /** @type {Part[]} */ var noWarn = [];
  /** @type {Part[]} */ var warnOnly = [];
  for(var j=0;j<cands.length;j++){
    var p = cands[j];
    if(!_mulletWheelOK(theme, slotKey, p)) continue;
    /** @type {Build} */ var test = Object.assign({}, base); test[slotKey] = p;
    var after = checkBuild(test);
    var newErr = false;
    for(var e=0;e<after.errors.length;e++){ if(beforeE.indexOf(verdictKey(after.errors[e]))<0){ newErr = true; break; } }
    if(newErr) continue;
    var newWarn = false;
    for(var w2=0;w2<after.warnings.length;w2++){ if(beforeW.indexOf(verdictKey(after.warnings[w2]))<0){ newWarn = true; break; } }
    (newWarn ? warnOnly : noWarn).push(p);
  }
  var pool = noWarn.length ? noWarn : warnOnly;
  return _bandPick(pool, theme.band, rng);
}

/** Generate a fresh random build for a sample-build theme. The result is
 * complete per slotRequired() and error-free, or {ok:false} after the attempt
 * budget is spent (the UI then loads its fixed fallback build for the theme and
 * says so). Optional slots (bb/headset/grips) are included on a coin flip;
 * slots the frame makes non-required (hardtail shock, DH dropper, integrated-
 * freehub cassette) are skipped. Presets are ignored - every slot is an
 * individual part, so presetBy stays empty. RNG is injectable for tests;
 * defaults to Math.random.
 * @param {string} themeKey @param {function():number} [rng] @param {{attempts?: number}} [opts]
 * @returns {SampleBuildResult} */
function generateSampleBuild(themeKey, rng, opts){
  var rand = rng || Math.random;
  var attempts = (opts && opts.attempts) || 200;
  /** @type {SampleTheme|null} */ var theme = null;
  for(var t=0;t<SAMPLE_THEMES.length;t++){ if(SAMPLE_THEMES[t].key===themeKey){ theme = SAMPLE_THEMES[t]; break; } }
  if(!theme) return { ok:false, theme:null };
  var themeRef = theme;
  var frames = /** @type {FramePart[]} */ (_partsByCat('frame')).filter(function(f){ return themeRef.frame(f); });
  for(var att=0; att<attempts; att++){
    /** @type {Build} */ var build = {};
    var frame = /** @type {FramePart|null} */ (_bandPick(frames, theme.band, rand));
    if(!frame) break;                       // theme matches no frame at all
    build.frame = frame;
    var dead = false;
    for(var s=0;s<_SAMPLE_PLAN.length;s++){
      var key = _SAMPLE_PLAN[s];
      var slot = _slotByKey(key);
      if(!slot) continue;
      var rw = effectiveWheel(build, 'rear');
      var required = slotRequired(slot, frame, rw);
      if(!required){
        // Optional slots (bb/headset/grips): include on a coin flip. Slots made
        // NON-required by the frame are skipped - filling a hardtail's shock,
        // a DH bike's dropper or an integrated-freehub wheel's cassette would
        // add a conflict or misrepresent the theme.
        if(slot.optional && rand() < 0.5){ /* include it */ } else { continue; }
      }
      var pick = _sampleSlotPick(build, key, theme, rand);
      if(!pick){ if(required){ dead = true; break; } continue; }
      build[key] = pick;
    }
    if(dead) continue;
    // Final honesty gates: zero errors AND complete per slotRequired.
    var res = checkBuild(build);
    if(res.errors.length) continue;
    var rwf = effectiveWheel(build, 'rear');
    var incomplete = false;
    for(var m=0;m<SLOTS.length;m++){ if(slotRequired(SLOTS[m], frame, rwf) && !wheelPositionFilled(build, SLOTS[m].key)){ incomplete = true; break; } }
    if(incomplete) continue;
    /** @type {Object.<string, string>} */ var ids = {};
    Object.keys(build).forEach(function(k){ var bp = build[k]; if(bp) ids[k] = bp.id; });
    return { ok:true, theme:theme, build:ids, presetBy:{}, frameId:frame.id, warnings:res.warnings.length };
  }
  return { ok:false, theme:theme };
}

/* =============================================================================
   SHARED DISPLAY / PROVENANCE HELPERS (used by both the UI and the tests, so the
   "verified" badge logic and HTML-escaping have one tested source of truth)
   ========================================================================== */
/** Escape a value for safe interpolation into HTML (element AND attribute text).
 * @param {*} s @returns {string} */
function esc(s){
  return String(s == null ? '' : s)
    .replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;')
    .replace(/"/g, '&quot;').replace(/'/g, '&#39;');
}

/** Effective weight of a part in grams. Presets/kits DERIVE their weight from
 * the parts they fill (weight is never stored on a kit - a stored figure
 * drifts into physically impossible bundles, REVIEW.md #12); components use
 * their own figure. Returns null when unknown or incomplete.
 * @param {Part|null|undefined} p @returns {number|null} */
function partWeight(p){
  if(!p) return null;
  if('fills' in p && p.fills){
    var ks = Object.keys(p.fills), sum = 0;
    if(!ks.length) return null;
    for(var i=0;i<ks.length;i++){
      var c = byId(p.fills[ks[i]]);
      if(!c || typeof c.weight !== 'number') return null;
      sum += c.weight;
    }
    return sum;
  }
  return (typeof p.weight === 'number') ? p.weight : null;
}

/** Sanitize the decoded payload of a "#b=" share link (also the build-comparison
 * paste box). Ids resolve through canonicalId first (ids are append-only, so a
 * link minted before an id retired must keep working). A build entry survives
 * only when the slot key is a real slot, the part exists, AND the part's
 * category matches the slot's expected category — without the category check a
 * stale/corrupted/crafted link can inject e.g. a tire into the fork slot and
 * checkBuild emits nonsense ("Steerer mismatch: Fork is undefined…") instead of
 * the link being cleanly rejected. A preset survives only when it belongs to
 * the group it claims (REVIEW.md #25 — a crafted link could otherwise bill one
 * group as another's kit). Unknown keys are dropped, never crashed on, so links
 * minted by a newer app version still load what they can.
 * @param {Object.<string, *>|null|undefined} bsrc raw slotKey -> part id
 * @param {Object.<string, *>|null|undefined} psrc raw groupKey -> preset id
 * @returns {{build: Object.<string, string>, presetBy: Object.<string, string>}} */
function sanitizeShare(bsrc, psrc){
  /** @type {Object.<string, string>} */ var build = {};
  /** @type {Object.<string, string>} */ var presetBy = {};
  /** @type {Object.<string, string>} */ var slotCat = {};
  SLOTS.forEach(function(s){ slotCat[s.key] = s.cat; });
  Object.keys(bsrc || {}).forEach(function(k){
    var id = canonicalId((bsrc || {})[k]); var p = typeof id === 'string' ? byId(id) : null;
    if(typeof id === 'string' && p && slotCat[k] && p.cat === slotCat[k]) build[k] = id;
  });
  Object.keys(psrc || {}).forEach(function(k){
    var id = canonicalId((psrc || {})[k]); var p = typeof id === 'string' ? byId(id) : null;
    var g = null;
    for(var i = 0; i < GROUPS.length; i++){ if(GROUPS[i].key === k){ g = GROUPS[i]; break; } }
    if(typeof id === 'string' && g && g.preset && p && p.cat === g.preset.cat) presetBy[k] = id;
  });
  /* Seatpost mutex (ONE physical post): unify-seatpost made the dropper + rigid
     slots mutually exclusive, but a link minted BEFORE the unification — or a
     hand-edited one — can still carry both (they used to be independent slots).
     Keep the one the frame defaults to (defaultSeatpostCat) and drop the other,
     so a loaded build never double-counts a dropper AND a rigid post. */
  if(build.dropper && build.seatpost){
    var keep = defaultSeatpostCat(build.frame ? byId(build.frame) : null);
    delete build[keep === 'dropper' ? 'seatpost' : 'dropper'];
  }
  return { build: build, presetBy: presetBy };
}

/** Is this part verified against a manufacturer source? A preset/kit counts as
 * verified only when every part it fills is itself verified.
 * @param {Part|null|undefined} p @returns {boolean} */
function partVerified(p){
  if(!p) return false;
  if('fills' in p && p.fills){
    var ks = Object.keys(p.fills);
    return ks.length > 0 && ks.every(function(s){ var c = byId(p.fills[s]); return !!(c && c.verified === true); });
  }
  return p.verified === true;
}

/* ---- Export for Node tests (ignored by the browser) ---------------------- */
if (typeof module !== 'undefined' && module.exports) {
  module.exports = { PARTS:PARTS, GROUPS:GROUPS, SLOTS:SLOTS, LABELS:LABELS, WHEEL_CONFIG:WHEEL_CONFIG, slotRequired:slotRequired,
    altSlotsOf:altSlotsOf, wheelPositionFilled:wheelPositionFilled, defaultSeatpostCat:defaultSeatpostCat, effectiveWheel:effectiveWheel,
    ALIASES:ALIASES, canonicalId:canonicalId,
    byId:byId, nameOf:nameOf, specSummary:specSummary, checkBuild:checkBuild, Verdict:Verdict, verdictKey:verdictKey,   // Verdict exported for src/compat-bmx.js - both engines share the verdict primitives, never copy them
    rotorOverMax:rotorOverMax,   // exported so tools/verdict-audit-harness.js's own rotor-max probe shares the engine's tolerance instead of re-deriving it
    placementDiff:placementDiff, conflictReason:conflictReason, compatOf:compatOf, bundleActive:bundleActive, buildTotals:buildTotals,
    esc:esc, partVerified:partVerified, partWeight:partWeight, sanitizeShare:sanitizeShare,
    mulberry32:mulberry32, fisherYatesShuffle:fisherYatesShuffle, SAMPLE_THEMES:SAMPLE_THEMES, generateSampleBuild:generateSampleBuild };
}
